#include<bits/stdc++.h>
using namespace std;
int main(void){
    long long n,a[4005][4005]={0},maxn=0-0xfffffffffff;
    cin>>n;
    for(int i=1;i<=n;i++){
    	for(int j=1;j<=n;j++){
    		cin>>a[i][j];
		}
	}
	for(int i=1;i<=n;i++){
		long long sua=0,sub=0;
    	for(int j=1;j<=n;j++){
    		sua+=a[i][j];
    		sub+=a[j][i];
		}
		maxn=max(maxn,max(sua,sub));
	}
    for(int i=2;i<=n*2;i++){
        long long sum=0;
        for(int j=1;j<=n;j++)
            if(1<=i-j&&i-j<=n)sum+=a[j][i-j];
        maxn=max(maxn,sum);
    }
    for(int i=2;i<=n-1;i++){
        long long sum=0;
        for(int j=1;j<=n;j++)
            if(1<=j-i&&j-i<=n)sum+=a[j][j-i];
        maxn=max(maxn,sum);
    }
	cout<<maxn;
    return false;
}
